import prometheus_client
from sqlalchemy import create_engine

# Define metric families
username_metric = prometheus_client.Gauge('db_connection_username', 'Database username', ['host', 'database'])
password_metric = prometheus_client.Gauge('db_connection_password', 'Database password', ['host', 'database'])
host_metric = prometheus_client.Gauge('db_connection_host', 'Database host', ['database'])
connection_string_metric = prometheus_client.Gauge('db_connection_string', 'Database connection string', ['database'])

def monitor_database(username, password, host, database, connection_string):
    try:
        engine = create_engine(connection_string)
        engine.connect()

        # Set metric values
        username_metric.labels(host=host, database=database).set(username)
        password_metric.labels(host=host, database=database).set(password)
        host_metric.labels(database=database).set(host)
        connection_string_metric.labels(database=database).set(connection_string)

        # Close the engine connection
        engine.dispose()
    except Exception as e:
        # Log the error and set metric values to indicate failure
        print(f"Error connecting to database: {e}")
        username_metric.labels(host=host, database=database).set(-1)
        password_metric.labels(host=host, database=database).set(-1)
        host_metric.labels(database=database).set(-1)
        connection_string_metric.labels(database=database).set(-1)

if __name__ == '__main__':
    # Set your database credentials here
    username = "your_username"
    password = "your_password"
    host = "your_host"
    database = "your_database"
    connection_string = "your_connection_string"

    # Monitor the database
    monitor_database(username, password, host, database, connection_string)

    # Start the Prometheus client
    prometheus_client.start_http_server(port=8080)